Create Spreadsheet Row.code:
// Append a single row to the bottom of a sheet.
appendValues({
  // 1) Spreadsheet ID — the long string from the sheet's URL.
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // 2) Where to append. Use the sheet name + column range.
  range: 'Sheet1!A1:D1',
  // 3) Outer array = rows, inner arrays = cells in column order.
  values: [
    [$.data.name, $.data.email, $.data.amount, $.data.date],
  ],
});

Create Multiple Spreadsheet Rows.code:
// Append many rows in one call.
// Each inner array is one row; cells must line up with your columns.
appendValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  range: 'Sheet1!A1:D1',
  values: $.data.records.map(r => [r.name, r.email, r.amount, r.date]),
});

Update Spreadsheet Row.code:
// Overwrite one or more ranges with new values.
// Each entry in `data` targets a specific A1 range.
batchUpdateValues({
  spreadsheetId: '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // Cells are parsed like a user typed them (formulas, dates, etc.).
  valueInputOption: 'USER_ENTERED',
  data: [
    {
      range: 'Sheet1!A5:D5',
      values: [[$.data.name, $.data.email, $.data.amount, $.data.date]],
    },
  ],
});

Get Data Range.code:
// Read values from a range. Result is on state.data as a 2d array.
getValues(
  // 1) Spreadsheet ID.
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  // 2) A1 range — sheet name + range.
  'Sheet1!A1:D100'
);

Lookup Spreadsheet Row.code:
// Read the column, then filter in JS to find the matching row.
getValues(
  '1O-a4_RgPF_p8W3I6b5M9wobA3-CBW8hLClZfUik5sos',
  'Sheet1!A1:D100',
  // The callback receives state with the rows on state.data.values.
  state => {
    const [header, ...rows] = state.data.values || [];
    // Match on the second column (index 1).
    state.match = rows.find(r => r[1] === $.data.email);
    return state;
  }
);
